function foodNameEN(n) {
  try {
    const l = (typeof getLang === 'function') ? getLang() : (localStorage.getItem('nlang') || 'it');
    return l === 'en' ? (FOOD_EN[n] || n) : n;
  } catch (e) { return n; }
}
function foodCatEN(c) {
  try {
    const l = (typeof getLang === 'function') ? getLang() : (localStorage.getItem('nlang') || 'it');
    return l === 'en' ? (FOOD_CAT_EN[c] || c) : c;
  } catch (e) { return c; }
}

function rebuildDB() {
  ALL_DB=[...DB_CREA,...DB_BDA,...DB_ONS,...DB_APROTEICI,...DB_FLAVIS,...DB_UPF,...DB_EXTRA,...CUSTOM_DB,...RICETTE_DB.map(r=>r._dbEntry).filter(Boolean)];
  FOOD_MAP={};
  ALL_DB.forEach(f=>{FOOD_MAP[f.n.toLowerCase()]=f;});
}

// Carica gli alimenti personalizzati dell'utente da Supabase e ricostruisce ALL_DB.
// Disponibile in tutte le pagine che includono db.js + utils.js.
async function loadCustomFoods() {
  if (!currentUser || !sb) {
    console.warn('loadCustomFoods: currentUser o sb non disponibili');
    return;
  }
  try {
    const { data, error } = await sb
      .from('alimenti_custom')
      .select('*')
      .eq('user_id', currentUser.id)
      .order('nome');
    if (error) {
      console.error('loadCustomFoods error:', error.message);
      if (typeof toast === 'function') toast('Errore caricamento alimenti personalizzati: ' + error.message, 'err');
      return;
    }
    CUSTOM_DB = (data || []).map(r => ({
      _id:  r.id,
      n:    r.nome,
      c:    r.categoria || '',
      src:  'PERS',
      k:    r.kcal,
      p:    r.proteine,
      gs:   r.grassi_saturi,
      g:    r.grassi_tot,
      z:    r.zuccheri,
      ch:   r.carboidrati,
      fi:   r.fibre,
      ca:   r.calcio,
      fe:   r.ferro,
      mg:   r.magnesio,
      k2:   r.potassio,
      na:   r.sodio,
      zn:   r.zinco,
      fo:   r.fosforo,
      se:   r.selenio,
      col:  r.colesterolo
    }));
    rebuildDB();
    console.log('loadCustomFoods: caricati', CUSTOM_DB.length, 'alimenti personalizzati');
  } catch(e) {
    console.error('loadCustomFoods exception:', e.message);
    if (typeof toast === 'function') toast('Errore alimenti personalizzati: ' + e.message, 'err');
  }
}

